250→  const main = extractMainCommand(words);
251→  if (!main) {
252→    if (redirectionTargets.length > 0) {
253→      return { isWriteLike: true, targets: redirectionTargets };
254→    }
255→    return { isWriteLike: false, targets: [] };
256→  }
257→
258→  const { name, args } = main;
259→  const lower = name.toLowerCase();
260→  const commandTargets: string[] = [];
261→  let isWriteLike = redirectionTargets.length > 0;
262→
263→  if (lower === "tee") {
264→    const files = args.filter((arg) => !arg.startsWith("-"));
265→    if (files.length > 0) {
266→      isWriteLike = true;
267→      commandTargets.push(...files);
268→    }
269→  } else if (["touch", "mkdir", "rm", "rmdir", "truncate"].includes(lower)) {
270→    const files = args.filter((arg) => !arg.startsWith("-"));
271→    if (files.length > 0) {
272→      isWriteLike = true;
273→      commandTargets.push(...files);
274→    }
275→  } else if (["cp", "mv", "install"].includes(lower)) {
276→    const positional = args.filter((arg) => !arg.startsWith("-"));
277→    if (positional.length >= 2) {
278→      isWriteLike = true;
279→      commandTargets.push(positional[positional.length - 1] || "");
280→    }
281→  } else if (lower === "sed" || lower === "perl") {
282→    if (args.some((arg) => arg === "-i" || arg.startsWith("-i"))) {
283→      const positional = args.filter((arg) => !arg.startsWith("-"));
284→      const last = positional[positional.length - 1];
285→      if (last) {
286→        isWriteLike = true;
287→        commandTargets.push(last);
288→      }
289→    }
290→  }
291→
292→  if (!isWriteLike) {
293→    return { isWriteLike: false, targets: [] };
294→  }
295→
296→  return {
297→    isWriteLike: true,
298→    targets: dedupe([...redirectionTargets, ...commandTargets]).filter(
299→      (target) => target.length > 0,
300→    ),
301→  };
302→}
303→
304→function extractMainCommand(
305→  words: string[],
306→): { name: string; args: string[] } | null {
307→  let index = 0;
308→  while (index < words.length) {
309→    const token = words[index];
310→    if (!token) {
311→      index += 1;
312→      continue;
313→    }
314→    if (isVariableAssignment(token)) {
315→      index += 1;
316→      continue;
317→    }
318→    return {
319→      name: token,
320→      args: words.slice(index + 1),
321→    };
322→  }
323→  return null;
324→}
325→
326→function isVariableAssignment(token: string): boolean {
327→  return /^[A-Za-z_][A-Za-z0-9_]*=/.test(token);
328→}
329→
330→function extractRedirectionTargets(words: string[]): string[] {
331→  const targets: string[] = [];
332→
333→  for (let i = 0; i < words.length; i++) {
334→    const token = words[i];
335→    if (!token) {
336→      continue;
337→    }
338→
339→    if (isRedirectionToken(token)) {
340→      const next = words[i + 1];
341→      if (
342→        next &&
343→        !next.startsWith("&") &&
344→        !isStderrRedirection(token) &&
345→        next !== "/dev/null"
346→      ) {
347→        targets.push(next);
348→      }
349→      continue;
350→    }
351→
352→    const inline = token.match(/^(\d*)(>>?|>\|)(.+)$/);
353→    if (inline?.[3] && !inline[3].startsWith("&")) {
354→      if (inline[1] !== "2" && inline[3] !== "/dev/null") {
355→        targets.push(inline[3]);
356→      }
357→    }
358→  }
359→
360→  return targets;
361→}
362→
363→function isRedirectionToken(token: string): boolean {
364→  return /^(?:\d*>>?|\d*>\|)$/.test(token);
365→}
366→
367→function isStderrRedirection(token: string): boolean {
368→  return /^2(>>?|>\|)$/.test(token);
369→}
370→
371→function splitShellWords(command: string): string[] {
372→  const matches = command.match(/"[^"]*"|'[^']*'|\S+/g) || [];
373→  return matches.map((word) => stripQuotes(word));
374→}
375→
376→function stripQuotes(value: string): string {
377→  if (
378→    (value.startsWith('"') && value.endsWith('"')) ||
379→    (value.startsWith("'") && value.endsWith("'"))
380→  ) {
381→    return value.slice(1, -1);
382→  }
383→  return value;
384→}
385→
386→function computePlanHash(content: string): string {
387→  const stripped = content.replace(REVIEW_MARKER_REGEX, "").trimEnd();
388→  return createHash("sha256").update(stripped, "utf-8").digest("hex");
389→}
390→
391→function extractLatestAutoReviewMarker(
392→  content: string,
393→): AutoReviewMarker | null {
394→  const matches = content.match(REVIEW_MARKER_REGEX);
395→  if (!matches || matches.length === 0) {
396→    return null;
397→  }
398→
399→  const latest = matches[matches.length - 1];
400→  if (!latest) {
401→    return null;
402→  }
403→
404→  let verdict = "";
405→  let hash = "";
406→  const fields = latest.matchAll(/(\w+)=([^;]+)/g);
407→  for (const field of fields) {
408→    const key = field[1]?.trim();
409→    const value = field[2]?.trim();
410→    if (!key || !value) {
411→      continue;
412→    }
413→    if (key === "verdict") {
414→      verdict = value;
415→    } else if (key === "hash") {
416→      hash = value;
417→    }
418→  }
419→
420→  if (verdict.length === 0 || hash.length === 0) {
421→    return null;
422→  }
423→
424→  return { verdict, hash };
425→}
426→
427→function isRecord(value: unknown): value is Record<string, unknown> {
428→  return typeof value === "object" && value !== null;
429→}
430→
431→function dedupe(values: string[]): string[] {
432→  return [...new Set(values)];
433→}
434→
435→export default hook;
436→
437→if (import.meta.main) {
438→  const { runHook } = await import("cc-hooks-ts");
439→  await runHook(hook);
440→}
