  });

  it("allows Write after plan approval", async () => {
    const repo = createWorkflowRepo(approvedWorkflowRepo());
    envHelper.set("CLAUDE_TEST_CWD", repo);

    const context = createPreToolUseContextFor(hook, "Write", {
      file_path: "src/a.ts",
